import { useCallback } from "react";
import Particles from "@tsparticles/react";
import { loadSlim } from "tsparticles-slim";

export default function LogisticsParticles(){

 const particlesInit = useCallback(async(engine)=>{
   await loadSlim(engine);
 },[]);

 const options={

  fullScreen:{
   enable:true,
   zIndex:0
  },

  background:{
   color:"transparent"
  },

  particles:{

   number:{
    value:140,
    density:{enable:true,area:900}
   },

   color:{
    value:["#7ddf64","#c7fab6","#9ae6b4"]
   },

   shape:{
    type:"circle"
   },

   opacity:{
    value:0.6
   },

   size:{
    value:{min:2,max:6}
   },

   links:{
    enable:true,
    distance:150,
    color:"#b8f7a7",
    opacity:0.35,
    width:1.2
   },

   move:{
    enable:true,
    speed:1.5,
    direction:"none",
    outModes:{default:"bounce"}
   }

  },

  interactivity:{

   events:{
    onHover:{
     enable:true,
     mode:"repulse"
    }
   },

   modes:{
    repulse:{
     distance:120,
     duration:0.4
    }
   }

  }

 };

 return <Particles init={particlesInit} options={options}/>;

}
